import Player from "./player.js";

export default class MainScene extends Phaser.Scene{
    constructor(){
        super("MainScene");
    }
    preload(){
      Player.preload(this);
        this.load.image('tiles','assets/images/tilemap.png');
        this.load.tilemapTiledJSON('map','assets/images/map.json');
    }
    create() {
        const map = this.make.tilemap({key:'map'});

        const activeTilesets = map.tilesets
            .map(t => map.addTilesetImage(t.name, 'tiles'))
            .filter(t => t != null);

        map.layers.forEach(layer => {
            if (layer) {
                map.createLayer(layer.name, activeTilesets, 0, 0);
            }
        });

        this.matter.world.setBounds(0, 0, 2000, 2000);

        this.player = new Player({scene: this, x: 32, y: 32, texture: 'you', frame: 'knight_idle_1'});

        this.player.inputKeys = this.input.keyboard.addKeys({
            up: Phaser.Input.Keyboard.KeyCodes.W,
            down: Phaser.Input.Keyboard.KeyCodes.S,
            left: Phaser.Input.Keyboard.KeyCodes.A,
            right: Phaser.Input.Keyboard.KeyCodes.D,
        });

        this.cameras.main.setBounds(0, 0, 2048, 2048);
        this.cameras.main.startFollow(this.player, false, 0.1, 0.1);

        this.time.addEvent({
            delay: 5000,
            callback: this.triggerEncounter,
            callbackScope: this,
            loop: true
        });
    }

    triggerEncounter() {
        console.log("Encounter triggered! React will handle the UI.");
    }

    update(){
        this.player.update();
    }
}

import Player from "./player.js";

export default class MainScene extends Phaser.Scene{
    constructor(){
        super("MainScene");
    }
    preload(){
      Player.preload(this);
        this.load.image('tiles','assets/images/tilemap.png');
        this.load.tilemapTiledJSON('map','assets/images/map.json');
    }
    create() {
        const map = this.make.tilemap({key:'map'});

        const activeTilesets = [];
        // Attempt to load tilesets safely. The provided tilemap.png dimensions might not match map.json metadata perfectly.
        map.tilesets.forEach(t => {
            try {
                // If the name is undefined (external TSX), or if we don't have its image, this might fail softly or return null
                if (t && t.name) {
                    const ts = map.addTilesetImage(t.name, 'tiles');
                    if (ts) activeTilesets.push(ts);
                }
            } catch (e) {
                console.warn("Failed to load tileset:", t.name, e);
            }
        });

        map.layers.forEach(layer => {
            if (layer) {
                try {
                    map.createLayer(layer.name, activeTilesets, 0, 0);
                } catch (e) {
                    console.warn("Failed to create layer:", layer.name, e.message);
                }
            }
        });

        this.matter.world.setBounds(0, 0, 2000, 2000);

        this.player = new Player({scene: this, x: 32, y: 32, texture: 'you', frame: 'knight_idle_1'});

        this.player.inputKeys = this.input.keyboard.addKeys({
            up: Phaser.Input.Keyboard.KeyCodes.W,
            down: Phaser.Input.Keyboard.KeyCodes.S,
            left: Phaser.Input.Keyboard.KeyCodes.A,
            right: Phaser.Input.Keyboard.KeyCodes.D,
        });

        this.cameras.main.setBounds(0, 0, 2048, 2048);
        this.cameras.main.startFollow(this.player, false, 0.1, 0.1);

        this.time.addEvent({
            delay: 5000,
            callback: this.triggerEncounter,
            callbackScope: this,
            loop: true
        });
    }

    triggerEncounter() {
        console.log("Encounter triggered! React will handle the UI.");
    }

    update(){
        this.player.update();
    }
}
